import{_ as i,o as e,c as t,ai as p}from"./chunks/framework.CEhIufms.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"problems/2026/w02/report.md","filePath":"problems/2026/w02/report.md"}'),r={name:"problems/2026/w02/report.md"};function a(o,l,s,_,n,c){return e(),t("div",null,[...l[0]||(l[0]=[p("<p>YCup Stage 2 战报</p><p>YCup Stage 2 : Nanjing 于今天中午在 305 教室圆满落幕。</p><p>高二（12）班队伍牛大队以 11 题（共 12 题）的成绩夺魁。</p><p>以下是完整排行榜：</p><ol><li>第一名 牛大队 11/194</li><li>第二名 想得出队名 10/174</li><li>第三名 王以神了 9/189</li><li>第四名 还没想好队名 8/127</li><li>第五名 SLD 战队 8/147</li><li>第六名 一回合，一次 7/162</li><li>第七名 0D000721 6/110</li><li>第八名 1048576 6/133</li></ol><p>Fun Facts：</p><ul><li>牛大队以绝对的数学竞赛水平再次夺魁，但没有如愿阿克（全对）。</li><li>我们加入了自动化记分系统和观众席，让本次比赛的组织更为有序。感谢所有组织人员、出题人、王以老师的大力支持。</li><li>王以神了 队在前十分钟表现较为挣扎，但快速翻盘到了全场第三名。</li><li>我们仍然没有等到女参赛选手，因而最佳女选手奖金继续空缺。但是本次的出题人包括clw同学，感谢她的贡献——她提供了若干道质量和难度合适的题目。</li><li>王以（老师）神了。</li></ul><p>如果需要题目、答案、报名参赛或了解更多事宜，欢迎加我微信。 下一场（YCup Stage 3:缘之空，暂定）将由高二（12）班的四位同学出题，欢迎大家踊跃参与。</p>",8)])])}const u=i(r,[["render",a]]);export{d as __pageData,u as default};
